import boto3
from botocore.exceptions import ClientError

def create_sns_subscription(topic_arn, endpoint):
    try:
        sns = boto3.client('sns')
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        print(f'SNS subscription created: {response["SubscriptionArn"]}')
    except ClientError as e:
        if e.response['Error']['Code'] == 'InvalidParameter':
            print('Error creating SNS subscription:', e)
        else:
            raise

def main():
    topic_arn = input("Enter the SNS Topic ARN: ")
    endpoint = input("Enter the URL to subscribe (HTTPS): ")

    create_sns_subscription(topic_arn, endpoint)

if __name__ == "__main__":
    main()